#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <json-c/json.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char line[10000];
        if (!fgets(line, sizeof(line), stdin)) break;
        // remove possible trailing newline
        line[strcspn(line, "\n")] = '\0';
        struct json_object *root = json_tokener_parse(line);
        struct json_object *students;
        if (!json_object_object_get_ex(root, "students", &students)) {
            printf("Name\tCGPA\tAge\n");
            json_object_put(root);
            continue;
        }
        int n = json_object_array_length(students);
        printf("Name\tCGPA\tAge\n");
        for (int i = 0; i < n; ++i) {
            struct json_object *stu = json_object_array_get_idx(students, i);
            struct json_object *tmp;
            const char *name = "N/A";
            const char *cgpa = "N/A";
            const char *age = "N/A";
            if (json_object_object_get_ex(stu, "name", &tmp))
                name = json_object_get_string(tmp);
            if (json_object_object_get_ex(stu, "CGPA", &tmp)) {
                static char buf[32];
                snprintf(buf, sizeof(buf), "%g", json_object_get_double(tmp));
                cgpa = buf;
            }
            if (json_object_object_get_ex(stu, "age", &tmp)) {
                static char buf2[32];
                snprintf(buf2, sizeof(buf2), "%d", json_object_get_int(tmp));
                age = buf2;
            }
            printf("%s\t%s\t%s\n", name, cgpa, age);
        }
        json_object_put(root);
    }
    return 0;
}

