code.Java:
import java.io.*;
import java.util.*;
import org.json.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; ++tc) {
            String line = br.readLine();
            JSONObject root = new JSONObject(line);
            System.out.println("Name\tCGPA\tAge");
            if (!root.has("students")) continue;
            JSONArray arr = root.getJSONArray("students");
            for (int i = 0; i < arr.length(); ++i) {
                JSONObject stu = arr.getJSONObject(i);
                String name = stu.has("name") ? stu.getString("name") : "N/A";
                String cgpa = stu.has("CGPA") ? String.valueOf(stu.getDouble("CGPA")) : "N/A";
                String age  = stu.has("age")  ? String.valueOf(stu.getInt("age"))    : "N/A";
                System.out.println(name + "\t" + cgpa + "\t" + age);
            }
        }
    }
}

