import sys, json

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    idx = 1
    for _ in range(T):
        if idx >= len(data):
            break
        line = data[idx].strip()
        idx += 1
        try:
            obj = json.loads(line)
        except json.JSONDecodeError:
            obj = {}
        print('Name\tCGPA\tAge')
        students = obj.get('students', [])
        for stu in students:
            name = stu.get('name', 'N/A')
            cgpa = str(stu.get('CGPA', 'N/A')) if 'CGPA' in stu else 'N/A'
            age = str(stu.get('age', 'N/A')) if 'age' in stu else 'N/A'
            print(f"{name}\t{cgpa}\t{age}")

if __name__ == "__main__":
    main()

